INSERT INTO "public"."aggregated_notice" VALUES
(47, JSON '"[{\"url\":\"https://canvas.tongji.edu.cn/courses/110856/announcements/72669\",\"label\":\"\u539f\u6587\"}]"', U&'\8bfe\7a0b', U&'Hello everyone. The final examination of the course "Software Engineering Management and Economics (No.42041301 & No.42041302)" will be held from 17th to 18th June 2026 at JiaDing campus. The examination related matters are now explained as follows: Submit the documentations of your team''s course project. The documentations of your team''s course project include: Design Specification of your project (SRS+SDS), According to the requirements of the software engineering course, write SRS and SDS. Report of Project Management and Economic Analysis , including but not limited to: project scope, project plan, software process monitoring & controlling, software process improvement, project risk management, project closure, estimation of size of software prototype, estimation of software costs, software pricing strategy, fund raising, financial evaluation of software product, financial risk management etc.. Source code of software prototype developed by your team members. Requirements about submission of documentations Before 23:59pm, 15th June 2026. Submit all above documentations on Canvas. Package all above files into one file (.zip), label the name of file(.zip) as "Team ID + Leader Student ID + Leader Name + Project Name\201d and upload the file on Canvas. After submission of the proposal, prepare PPT for final presentation. After completing your team\2019s presentation, submit PPT to the TA. Note: Name Format of the zip file: "Team ID + Leader Student ID + Leader Name + Project Name\201d. 2. Final Presentation Time and Venue 2.1 Time(two days): 2026.6.17 , 8:00am - 11:00am & 13:30pm - 16:10pm, Each Team: 8Min./Presentation + 10Min./Demo + 2Min./Q&A. 2025.6.18 , 8:00am - 11:00am & 13:30pm - 16:10pm, Each Team: 8Min./Presentation + 10Min./Demo + 2Min./Q&A. 2.2 Venue: B415 (Test room) \ff0c B413 (waiting room) Kind Regards HUANG Jie 2026.6.4', TIMESTAMP '2026-06-17 14:52:16.589894', NULL, '9225009', 'DONE', NULL, 'https://canvas.tongji.edu.cn/courses/110856/announcements/72669', TIMESTAMP '2026-06-04 02:48:48', JSON '"{\"type\":\"Announcement\",\"canvas_api\":true}"', U&'Canvas \4e2a\4eba\901a\77e5', 'ONLINE', 'Hello everyone. The final examination of the course "Software Engineering Management and Economics (No.42041301 & No.420...', JSON '"[\"Canvas\",\"\u8bfe\u7a0b\"]"', NULL, 'Notice on the Final Exam of the Course', TIMESTAMP '2026-06-17 17:29:06.619778', 8, 2, NULL, NULL),
